import React, { useState } from 'react';
import axios from 'axios';
import '../assets/styles/MicrosoftTeams.css';

const MicrosoftTeamsButton = () => {
  const [loading, setLoading] = useState(false);
  const [statusMessage, setStatusMessage] = useState('');

  const handleRequest = async (url, actionName) => {
    setLoading(true);
    setStatusMessage('');

    try {
      const response = await axios.post(url);

      if (response.data.success) {
        setStatusMessage(`${actionName} cu succes!`);
      } else {
        setStatusMessage(`Eroare la ${actionName.toLowerCase()}.`);
      }
    } catch (error) {
      setStatusMessage(`A apărut o eroare la conectarea cu serverul pentru ${actionName.toLowerCase()}.`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="teams-button-container">
      <button className="open-teams-btn" onClick={() => handleRequest('/shortcuts/teams/open-teams/', 'Deschiderea Microsoft Teams')} disabled={loading}>
        {loading ? 'Se deschide...' : 'Deschide Microsoft Teams'}
      </button>
      <button className="close-teams-btn" onClick={() => handleRequest('/shortcuts/teams/close-teams/', 'Închiderea Microsoft Teams')} disabled={loading}>
        {loading ? 'Se închide...' : 'Închide Microsoft Teams'}
      </button>

      {/* Butoane pentru navigare în diferitele secțiuni */}
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/activity/', 'Navigare la Activity')} disabled={loading}>
        <i className="fas fa-home"></i> Activity
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/chat/', 'Navigare la Chat')} disabled={loading}>
        <i className="fas fa-comments"></i> Chat
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/teams/', 'Navigare la Teams')} disabled={loading}>
        <i className="fas fa-users"></i> Teams
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/assignments/', 'Navigare la Assignments')} disabled={loading}>
        <i className="fas fa-tasks"></i> Assignments
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/calendar/', 'Navigare la Calendar')} disabled={loading}>
        <i className="fas fa-calendar-alt"></i> Calendar
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/calls/', 'Navigare la Calls')} disabled={loading}>
        <i className="fas fa-phone"></i> Calls
      </button>
      <button className="nav-btn" onClick={() => handleRequest('/shortcuts/teams/onedrive/', 'Navigare la OneDrive')} disabled={loading}>
        <i className="fas fa-cloud"></i> OneDrive
      </button>

      {statusMessage && <p>{statusMessage}</p>}
    </div>
  );
};

export default MicrosoftTeamsButton;
